    mpr_mapping_allocate_memory(struct mpr_softc *sc)
    {
        uint32_t dpm_pg0_sz;

        sc->mapping_table = malloc((sizeof(struct dev_mapping_table) *
            sc->max_devices), M_MPR, M_ZERO|M_NOWAIT);
